const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
const ALL = (1 << 30) - 1;
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const arr = input.slice(idx, idx + N);
  idx += N;
  let G = ALL;
  for (let v of arr) G &= v;
  let cur = ALL;
  let segments = 0;
  for (let v of arr) {
    cur &= v;
    if (cur === G) {
      segments++;
      cur = ALL;
    }
  }
  outputs.push(String(N - segments));
}
console.log(outputs.join('\n'));
